var paginationDoc = ComponentDoc{
	Attributes: []DocAttribute{
		{Name: "page", Type: "number", Default: "1", Reflected: true, Observed: true,
			Description: templ.Raw(
				"Active page (1-indexed). Two-way bind via " +
					"<code>data-attr:page</code> " +
					"<code>data-on:neo-pagination-change</code>.",
			)},
		{Name: "pages", Type: "number", Default: "1", Observed: true,
			Description: templ.Raw(
				"Total page count. <code>page</code> is clamped to " +
					"<code>[1, pages]</code> on every render.",
			)},
		{Name: "sibling-count", Type: "number", Default: "1", Observed: true,
			Description: templ.Raw(
				"Pages shown on each side of the active one. " +
					"Increase to make ±N navigation cheaper; the " +
					"adapt loop shrinks this first when the row " +
					"runs out of room.",
			)},
		{Name: "boundary-count", Type: "number", Default: "1", Observed: true,
			Description: templ.Raw(
				"Pages pinned at the start and end of the run. The " +
					"adapt loop shrinks it after the sibling " +
					"window has bottomed out at 0.",
			)},
		{Name: "disabled", Type: "boolean", Default: "false", Observed: true,
			Description: templ.Raw(
				"Greys every chip and ignores clicks. Useful while a " +
					"parent dataset is still loading.",
			)},
		{Name: "aria-label", Type: "string", Default: `"Pagination"`,
			Description: templ.Raw(
				"Set on the host's <code>role=\"navigation\"</code> " +
					"so screen readers announce the landmark.",
			)},
	},
	Slots: []DocSlot{
		{Name: "template[data-neo-pagination-prev]",
			Description: templ.Raw(
				"Inner HTML of the prev button. Captured once on " +
					"connect from a <code>&lt;template&gt;</code> " +
					"child; the kit re-uses it on every render. " +
					"Default (no template) is a single " +
					"<code>chevron-left</code> icon (icon-only " +
					"button). An <em>empty</em> template " +
					"(<code>&lt;template " +
					"data-neo-pagination-prev&gt;&lt;/template&gt;" +
					"</code>) opts out of the prev button entirely.",
			)},
		{Name: "template[data-neo-pagination-next]",
			Description: templ.Raw(
				"Same as the prev slot, on the right; default is " +
					"<code>chevron-right</code>, empty opts out.",
			)},
	},
	Events: []DocEvent{
		{Name: "neo-pagination-change", Detail: "{ page: number }", Bubbles: true,
			Description: templ.Raw(
				"Fires when the user picks a chip or clicks " +
					"prev / next. <code>page</code> is the new " +
					"active page; the host has already reflected " +
					"<code>page=</code> by the time the event " +
					"dispatches.",
			)},
	},
	CSSProps: []DocCSSProp{
		{Name: "--neo-pagination-gap", Default: "calc(var(--page-spacing, 0.25rem) * 1)",
			Description: templ.Raw("Gap between chips.")},
		{Name: "--neo-pagination-page-min", Default: "2.25rem",
			Description: templ.Raw("Minimum width and height of a page chip.")},
		{Name: "--neo-pagination-active-bg", Default: "var(--accent, currentColor)",
			Description: templ.Raw("Background of the active page chip.")},
		{Name: "--neo-pagination-active-color", Default: "var(--accent-fg, var(--page-bg, #fff))",
			Description: templ.Raw("Text color of the active page chip.")},
		{Name: "--neo-pagination-active-hover-bg", Default: "color-mix(in srgb, var(--neo-pagination-active-bg), #000 12%)",
			Description: templ.Raw("Active chip background on hover.")},
		{Name: "--neo-pagination-active-active-bg", Default: "color-mix(in srgb, var(--neo-pagination-active-hover-bg), #000 8%)",
			Description: templ.Raw("Active chip background while pressed.")},
	},
}

